package com.example.oidcclient.config;

import com.example.oidcclient.web.OidcAuthenticationFilter;
import com.fasterxml.jackson.databind.ObjectMapper;
import jakarta.servlet.http.HttpServletResponse;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.http.converter.FormHttpMessageConverter;
import org.springframework.http.converter.StringHttpMessageConverter;
import org.springframework.security.config.Customizer;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.crypto.keygen.Base64StringKeyGenerator;
import org.springframework.security.crypto.keygen.StringKeyGenerator;
import org.springframework.security.web.SecurityFilterChain;
import org.springframework.web.client.RestTemplate;

import java.nio.charset.StandardCharsets;
import java.util.List;

@Configuration
public class SecurityConfig {

    @Bean
    public SecurityFilterChain securityFilterChain(HttpSecurity http, OidcAuthenticationFilter oidcAuthenticationFilter) throws Exception {
        http
                .csrf(csrf -> csrf.disable())
                .authorizeHttpRequests(auth -> auth
                        .requestMatchers("/", "/login", "/oidc/callback", "/error").permitAll()
                        .anyRequest().authenticated()
                )
                .addFilterAfter(oidcAuthenticationFilter, org.springframework.security.web.authentication.AnonymousAuthenticationFilter.class)
                .logout(logout -> logout
                        .logoutUrl("/logout")
                        .logoutSuccessHandler((request, response, authentication) -> {
                            request.getSession(false).invalidate();
                            response.sendRedirect("/");
                        })
                )
                .exceptionHandling(ex -> ex
                        .authenticationEntryPoint((request, response, authException) -> response.sendRedirect("/login"))
                )
                .httpBasic(Customizer.withDefaults())
                .formLogin(form -> form.disable());

        return http.build();
    }

    @Bean
    public RestTemplate restTemplate() {
        RestTemplate restTemplate = new RestTemplate(List.of(
                new FormHttpMessageConverter(),
                new StringHttpMessageConverter(StandardCharsets.UTF_8)
        ));
        return restTemplate;
    }

    @Bean
    public StringKeyGenerator stateKeyGenerator() {
        return new Base64StringKeyGenerator(Base64StringKeyGenerator.DEFAULT_LENGTH);
    }

    @Bean
    public StringKeyGenerator nonceKeyGenerator() {
        return new Base64StringKeyGenerator(Base64StringKeyGenerator.DEFAULT_LENGTH);
    }

    @Bean
    public ObjectMapper objectMapper() {
        return new ObjectMapper();
    }
}

