package com.example.oidcclient.service;

import com.example.oidcclient.config.OidcClientProperties;
import com.example.oidcclient.model.TokenResponse;
import com.fasterxml.jackson.core.type.TypeReference;
import com.fasterxml.jackson.databind.ObjectMapper;
import org.springframework.http.*;
import org.springframework.stereotype.Service;
import org.springframework.util.LinkedMultiValueMap;
import org.springframework.util.MultiValueMap;
import org.springframework.web.client.RestTemplate;
import org.springframework.web.util.UriComponentsBuilder;

import java.nio.charset.StandardCharsets;
import java.util.Base64;
import java.util.Map;

@Service
public class OidcClientService {

    private final OidcClientProperties properties;
    private final RestTemplate restTemplate;
    private final ObjectMapper objectMapper;

    public OidcClientService(OidcClientProperties properties, RestTemplate restTemplate, ObjectMapper objectMapper) {
        this.properties = properties;
        this.restTemplate = restTemplate;
        this.objectMapper = objectMapper;
    }

    public String buildAuthorizationUrl(String state, String nonce) {
        return UriComponentsBuilder
                .fromUriString(properties.getAuthorizationUri())
                .queryParam("response_type", "code")
                .queryParam("client_id", properties.getClientId())
                .queryParam("redirect_uri", properties.getRedirectUri())
                .queryParam("scope", properties.getScope())
                .queryParam("state", state)
                .queryParam("nonce", nonce)
                .build(true)
                .toUriString();
    }

    public TokenResponse exchangeCodeForTokens(String code) {
        HttpHeaders headers = new HttpHeaders();
        headers.setContentType(MediaType.APPLICATION_FORM_URLENCODED);
        headers.setAccept(java.util.List.of(MediaType.APPLICATION_JSON));
        headers.set(HttpHeaders.AUTHORIZATION, basicAuth(properties.getClientId(), properties.getClientSecret()));

        MultiValueMap<String, String> form = new LinkedMultiValueMap<>();
        form.add("grant_type", "authorization_code");
        form.add("code", code);
        form.add("redirect_uri", properties.getRedirectUri());

        HttpEntity<MultiValueMap<String, String>> request = new HttpEntity<>(form, headers);
        ResponseEntity<TokenResponse> response = restTemplate.exchange(
                properties.getTokenUri(),
                HttpMethod.POST,
                request,
                TokenResponse.class
        );

        return response.getBody();
    }

    public Map<String, Object> parseIdTokenClaims(String idToken) {
        try {
            String[] parts = idToken.split("\\.");
            if (parts.length < 2) {
                throw new IllegalArgumentException("Invalid id_token");
            }
            byte[] payload = Base64.getUrlDecoder().decode(parts[1]);
            return objectMapper.readValue(payload, new TypeReference<Map<String, Object>>() {});
        } catch (Exception e) {
            throw new IllegalStateException("Failed to parse id_token claims", e);
        }
    }

    public Map<String, Object> fetchUserInfo(String accessToken) {
        HttpHeaders headers = new HttpHeaders();
        headers.setBearerAuth(accessToken);
        headers.setAccept(java.util.List.of(MediaType.APPLICATION_JSON));

        HttpEntity<Void> request = new HttpEntity<>(headers);
        ResponseEntity<String> response = restTemplate.exchange(
                properties.getUserInfoUri(),
                HttpMethod.GET,
                request,
                String.class
        );

        try {
            return objectMapper.readValue(response.getBody(), new TypeReference<Map<String, Object>>() {});
        } catch (Exception e) {
            throw new IllegalStateException("Failed to parse userinfo response", e);
        }
    }

    private String basicAuth(String username, String password) {
        String value = username + ":" + password;
        return "Basic " + Base64.getEncoder().encodeToString(value.getBytes(StandardCharsets.UTF_8));
    }
}

package com.example.oidcclient.web;

import com.example.oidcclient.model.OidcUserSession;
import jakarta.servlet.FilterChain;
import jakarta.servlet.ServletException;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;
import org.springframework.security.authentication.AbstractAuthenticationToken;
import org.springframework.security.core.authority.AuthorityUtils;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.stereotype.Component;
import org.springframework.web.filter.OncePerRequestFilter;

import java.io.IOException;

@Component
public class OidcAuthenticationFilter extends OncePerRequestFilter {

    public static final String SESSION_USER_KEY = "OIDC_USER_SESSION";

    @Override
    protected void doFilterInternal(HttpServletRequest request, HttpServletResponse response, FilterChain filterChain)
            throws ServletException, IOException {
        Object sessionUser = request.getSession(false) != null
                ? request.getSession(false).getAttribute(SESSION_USER_KEY)
                : null;

        if (sessionUser instanceof OidcUserSession oidcUserSession
                && SecurityContextHolder.getContext().getAuthentication() == null) {
            AbstractAuthenticationToken authentication = new AbstractAuthenticationToken(AuthorityUtils.createAuthorityList("ROLE_USER")) {
                @Override
                public Object getCredentials() {
                    return oidcUserSession.getAccessToken();
                }

                @Override
                public Object getPrincipal() {
                    return oidcUserSession;
                }
            };
            authentication.setAuthenticated(true);
            SecurityContextHolder.getContext().setAuthentication(authentication);
        }

        filterChain.doFilter(request, response);
    }
}

package com.example.oidcclient.web;

import com.example.oidcclient.model.OidcUserSession;
import com.example.oidcclient.model.TokenResponse;
import com.example.oidcclient.service.OidcClientService;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpSession;
import org.springframework.security.crypto.keygen.StringKeyGenerator;
import org.springframework.stereotype.Controller;
import org.springframework.ui.Model;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RequestParam;

import java.util.Map;
import java.util.Objects;

@Controller
public class OidcController {

    private static final String SESSION_STATE = "OIDC_STATE";
    private static final String SESSION_NONCE = "OIDC_NONCE";

    private final OidcClientService oidcClientService;
    private final StringKeyGenerator stateKeyGenerator;
    private final StringKeyGenerator nonceKeyGenerator;

    public OidcController(OidcClientService oidcClientService,
                          StringKeyGenerator stateKeyGenerator,
                          StringKeyGenerator nonceKeyGenerator) {
        this.oidcClientService = oidcClientService;
        this.stateKeyGenerator = stateKeyGenerator;
        this.nonceKeyGenerator = nonceKeyGenerator;
    }

    @GetMapping("/")
    public String home(HttpServletRequest request, Model model) {
        HttpSession session = request.getSession(false);
        Object user = session != null ? session.getAttribute(OidcAuthenticationFilter.SESSION_USER_KEY) : null;
        model.addAttribute("user", user);
        return "home";
    }

    @GetMapping("/login")
    public String login(HttpServletRequest request) {
        HttpSession session = request.getSession(true);
        String state = stateKeyGenerator.generateKey();
        String nonce = nonceKeyGenerator.generateKey();
        session.setAttribute(SESSION_STATE, state);
        session.setAttribute(SESSION_NONCE, nonce);
        return "redirect:" + oidcClientService.buildAuthorizationUrl(state, nonce);
    }

    @GetMapping("/oidc/callback")
    public String callback(@RequestParam("code") String code,
                           @RequestParam("state") String state,
                           HttpServletRequest request) {
        HttpSession session = request.getSession(true);
        String expectedState = (String) session.getAttribute(SESSION_STATE);
        String expectedNonce = (String) session.getAttribute(SESSION_NONCE);

        if (!Objects.equals(expectedState, state)) {
            throw new IllegalStateException("Invalid state");
        }

        TokenResponse tokenResponse = oidcClientService.exchangeCodeForTokens(code);
        Map<String, Object> claims = oidcClientService.parseIdTokenClaims(tokenResponse.getId_token());

        Object tokenNonce = claims.get("nonce");
        if (expectedNonce != null && tokenNonce != null && !Objects.equals(expectedNonce, String.valueOf(tokenNonce))) {
            throw new IllegalStateException("Invalid nonce");
        }

        Map<String, Object> userInfo = tokenResponse.getAccess_token() != null
                ? oidcClientService.fetchUserInfo(tokenResponse.getAccess_token())
                : java.util.Collections.emptyMap();

        OidcUserSession userSession = new OidcUserSession();
        userSession.setSubject(stringValue(claims.get("sub")));
        userSession.setUsername(firstNonBlank(
                stringValue(claims.get("preferred_username")),
                stringValue(claims.get("name")),
                stringValue(userInfo.get("preferred_username")),
                stringValue(userInfo.get("name")),
                userSession.getSubject()
        ));
        userSession.setEmail(firstNonBlank(
                stringValue(claims.get("email")),
                stringValue(userInfo.get("email"))
        ));
        userSession.setIdToken(tokenResponse.getId_token());
        userSession.setAccessToken(tokenResponse.getAccess_token());
        userSession.setRefreshToken(tokenResponse.getRefresh_token());
        userSession.setClaims(claims);
        userSession.setUserInfo(userInfo);

        session.setAttribute(OidcAuthenticationFilter.SESSION_USER_KEY, userSession);
        session.removeAttribute(SESSION_STATE);
        session.removeAttribute(SESSION_NONCE);

        return "redirect:/protected";
    }

    @GetMapping("/protected")
    public String protectedPage(HttpServletRequest request, Model model) {
        HttpSession session = request.getSession(false);
        Object user = session != null ? session.getAttribute(OidcAuthenticationFilter.SESSION_USER_KEY) : null;
        model.addAttribute("user", user);
        return "protected";
    }

    private String stringValue(Object value) {
        return value == null ? null : String.valueOf(value);
    }

    private String firstNonBlank(String... values) {
        for (String value : values) {
            if (value != null && !value.isBlank()) {
                return value;
            }
        }
        return null;
    }
}

package com.example.oidcclient.web;

import com.example.oidcclient.model.OidcUserSession;
import jakarta.servlet.http.HttpSession;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RestController;

@RestController
public class UserController {

    @GetMapping("/api/me")
    public Object me(HttpSession session) {
        Object user = session.getAttribute(OidcAuthenticationFilter.SESSION_USER_KEY);
        if (user instanceof OidcUserSession oidcUserSession) {
            return oidcUserSession;
        }
        return java.util.Map.of("authenticated", false);
    }
}

